import{_ as s,o as a,c as n,Q as e}from"./chunks/framework.6a72df8e.js";const l="/assets/2023-03-29_09_01_55_990.57d2a281.png",p="/assets/2023-03-29_09_06_03_264.bab01b98.png",o="/assets/2023-03-29_09_07_46_859.bb28435e.png",_=JSON.parse('{"title":"CloudFlare 代理 FastAPI 隐藏真实 IP","description":"","frontmatter":{"tags":["记录问题"],"date":"2023-3-29"},"headers":[{"level":2,"title":"修改域名的名称服务器","slug":"修改域名的名称服务器","link":"#修改域名的名称服务器","children":[]},{"level":2,"title":"申请 SSL 证书","slug":"申请-ssl-证书","link":"#申请-ssl-证书","children":[]},{"level":2,"title":"配置 Nginx","slug":"配置-nginx","link":"#配置-nginx","children":[]},{"level":2,"title":"开启FastAPI","slug":"开启fastapi","link":"#开启fastapi","children":[]},{"level":2,"title":"结束","slug":"结束","link":"#结束","children":[]}],"relativePath":"src/杂项/cf代理fastapi.md","lastUpdated":1700455155000}'),r={name:"src/杂项/cf代理fastapi.md"},t=e('<h1 id="cloudflare-代理-fastapi-隐藏真实-ip" tabindex="-1">CloudFlare 代理 FastAPI 隐藏真实 IP <a class="header-anchor" href="#cloudflare-代理-fastapi-隐藏真实-ip" aria-hidden="true">#</a></h1><p>这东西真是有很多坑啊~</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>CloudFlare 免费版不支持四级域名(sub4.sub3.example.com)</p></div><p>国内没备案的域名不可以使用 80 和 443 端口, 因此我把 fastapi 开在了 8011 端口, 但是 CF 不支持代理 8011 端口. 👉<a href="https://developers.cloudflare.com/fundamentals/get-started/reference/network-ports/" target="_blank" rel="noreferrer">CloudFlare 支持的端口</a></p><p>可以看到 CF 除了 80, 443 端口还支持一些其他端口的代理, 本文使用 <code>8443</code> 端口</p><h2 id="修改域名的名称服务器" tabindex="-1">修改域名的名称服务器 <a class="header-anchor" href="#修改域名的名称服务器" aria-hidden="true">#</a></h2><p>在 CF <a href="https://dash.cloudflare.com/" target="_blank" rel="noreferrer">控制台</a>添加站点, 然后 CF 会让我们在域名提供商处把 DNS 设置为 CF 提供的名称服务器</p><p>我的域名提供商是阿里云, 所以进入阿里云控制台修改 DNS:</p><p><img src="'+l+'" alt="图 1"></p><p>然后就成功把在 CF 控制台激活了我们的域名(全球 DNS 同步一般需要 48-72 小时, 所以我去睡了一觉)</p><h2 id="申请-ssl-证书" tabindex="-1">申请 SSL 证书 <a class="header-anchor" href="#申请-ssl-证书" aria-hidden="true">#</a></h2><p>在 CF 控制台点击一个域名进入仪表盘, 可以在侧栏看到 SSL/TLS 下有很多种证书: <img src="'+p+'" alt="图 2"></p><p>CF 代理模式大致如下:</p><p><img src="'+o+`" alt="图 3"></p><p>可以看到浏览器的请求首先发给 CF 服务器, 然后由 CF 服务器对我们的源服务器发起请求, 最后把我们的源服务器返回的内容返回给浏览器</p><p>然后我们就看可以理解这些不同的证书是怎么用的了.<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup></p><ol><li><strong>边缘证书</strong>: 由受信 CA 颁布的证书, 会被浏览器认为是安全的</li><li><strong>客户端证书</strong>: 客户端证书就是需要使用这个证书才能访问你的网站，否则 cf 会拦下</li><li><strong>源服务器证书</strong>: cloudflare 的自签证书, 只有 cf 自己会信任, 但如果不然通过 CF 代理,直接访问域名的话, 浏览器会显示不安全.</li></ol><p>所以我们要申请一个源服务器证书.</p><p>申请好之后会生成两个字符串. 分别是<code>源证书</code>和<code>私钥</code>, 需要把这两个保存到服务器上, 一会儿配置 nginx 开启 SSL 的时候需要.</p><p>我分别保存为<code>/root/cert/example.com.cert</code>, <code>/root/cert/example.com.key</code>. <code>xxx</code>是域名(比如: example.com)</p><h2 id="配置-nginx" tabindex="-1">配置 Nginx <a class="header-anchor" href="#配置-nginx" aria-hidden="true">#</a></h2><p>这里只给出server的配置方法.</p><div class="language-nginx line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki material-theme-palenight has-highlighted-lines" tabindex="0"><code><span class="line"><span style="color:#C792EA;">server</span><span style="color:#BABED8;"> {</span></span>
<span class="line"><span style="color:#BABED8;">   </span><span style="color:#89DDFF;"> listen </span><span style="color:#BABED8;">8443 ssl</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">   </span><span style="color:#89DDFF;"> server_name </span><span style="color:#BABED8;">example.com</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">   </span><span style="color:#89DDFF;"> ssl_certificate </span><span style="color:#BABED8;">/root/cert/exmaple.com.cert</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">   </span><span style="color:#89DDFF;"> ssl_certificate_key </span><span style="color:#BABED8;">/root/cert/example.com.key</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">    </span><span style="color:#C792EA;">location</span><span style="color:#BABED8;"> </span><span style="color:#FFCB6B;">/ </span><span style="color:#BABED8;">{</span></span>
<span class="line highlighted warning"><span style="color:#BABED8;">       </span><span style="color:#89DDFF;"> proxy_pass </span><span style="color:#BABED8;">http://localhost:8011</span><span style="color:#89DDFF;">;</span><span style="color:#BABED8;"> </span></span>
<span class="line"><span style="color:#BABED8;">       </span><span style="color:#89DDFF;"> proxy_set_header </span><span style="color:#BABED8;">Host </span><span style="color:#89DDFF;">$</span><span style="color:#BABED8;">host</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">       </span><span style="color:#89DDFF;"> proxy_set_header </span><span style="color:#BABED8;">X-Real-IP </span><span style="color:#89DDFF;">$</span><span style="color:#BABED8;">remote_addr</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">       </span><span style="color:#89DDFF;"> proxy_set_header </span><span style="color:#BABED8;">X-Forwarded-For </span><span style="color:#89DDFF;">$</span><span style="color:#BABED8;">proxy_add_x_forwarded_for</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">       </span><span style="color:#89DDFF;"> proxy_set_header </span><span style="color:#BABED8;">X-Forwarded-Proto https</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">    }</span></span>
<span class="line"><span style="color:#BABED8;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>我的fastapi开在8011端口, 因此proxy_passs设置为<code>http://localhost:8011</code></p><h2 id="开启fastapi" tabindex="-1">开启FastAPI <a class="header-anchor" href="#开启fastapi" aria-hidden="true">#</a></h2><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">uvicorn</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">app.main:app</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">--host</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">0.0</span><span style="color:#C3E88D;">.0.0</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">--port</span><span style="color:#BABED8;"> </span><span style="color:#F78C6C;">8011</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">--reload</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="结束" tabindex="-1">结束 <a class="header-anchor" href="#结束" aria-hidden="true">#</a></h2><p>到这里就配置完成了. 可以通过curl测试一下:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">curl</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">https://{YOUR</span><span style="color:#BABED8;"> </span><span style="color:#C3E88D;">DOMAIN}:8443</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p><a href="https://machbbs.com/hostloc/486252" target="_blank" rel="noreferrer">https://machbbs.com/hostloc/486252</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>`,31),c=[t];function i(d,h,D,y,B,F){return a(),n("div",null,c)}const b=s(r,[["render",i]]);export{_ as __pageData,b as default};
